    /*[ {metric:String} = 'write_bps', toFloat64(sum(written_bytes) * 1000 / nullIf(sum(query_duration_ms), 0)), ]*/
    /*[ {metric:String} = 'parts_inserted', toFloat64(sum(ProfileEvents['InsertedCompactParts'] + ProfileEvents['InsertedWideParts'])), ]*/
    /*[ {metric:String} = 'parts_inserted_avg', toFloat64(avg(ProfileEvents['InsertedCompactParts'] + ProfileEvents['InsertedWideParts'])), ]*/
    /*[ {metric:String} = 'marks_load_time', toFloat64(sum(ProfileEvents['WaitMarksLoadMicroseconds'])), ]*/
    /*[ {metric:String} = 'marks_miss_rate', toFloat64(sum(ProfileEvents['MarkCacheMisses']) / nullIf(sum(ProfileEvents['MarkCacheHits']) + sum(ProfileEvents['MarkCacheMisses']), 0)), ]*/
    /*[ {metric:String} = 'selected_parts', toFloat64(sum(ProfileEvents['SelectedParts'])), ]*/
    /*[ {metric:String} = 'selected_ranges', toFloat64(sum(ProfileEvents['SelectedRanges'])), ]*/
    /*[ {metric:String} = 'selected_marks', toFloat64(sum(ProfileEvents['SelectedMarks'])), ]*/
    /*[ {metric:String} = 'exceptions', toFloat64(countIf(exception_code != 0)), ]*/
    /*[ {metric:String} = 'open_files', toFloat64(sum(ProfileEvents['FileOpen'])), ]*/
    /*[ {metric:String} = 'external_processing_files', toFloat64(sum(ProfileEvents['ExternalProcessingFilesTotal'])), ]*/
    /*[ {metric:String} = 'threads1', toFloat64(max(peak_threads_usage)), ]*/
    /*[ {metric:String} = 'threads2', toFloat64(max(length(thread_ids))), ]*/
    /*[ {metric:String} = 'threads3', toFloat64(sum(ProfileEvents['RealTimeMicroseconds']) / nullIf(1000 * sum(query_duration_ms), 0)), ]*/
    1, toFloat64(count()),
    toFloat64(count())
  ) AS value
  FROM merge(system, '^part_log')
  WHERE event_time >= {from:DateTime} - INTERVAL 20 MINUTE
    AND event_time <= {to:DateTime} + INTERVAL 20 MINUTE
    AND event_type = 4
  GROUP BY t, table_name
  )
  ORDER BY count() OVER (PARTITION BY table_name) DESC, sum(value) OVER (PARTITION BY table_name) DESC
  LIMIT 100 BY t
)
WHERE t >= {from:DateTime} AND t <= {to:DateTime}
ORDER BY t, table_name

